// Add proper cleanup in batch processor
class BatchProcessor {
  constructor() {
    this.items = [];
  }

  process(batch) {
    this.items.push(...batch);
    // Process items
    const results = this.items.map(item => this.processItem(item));

    // Clear processed items to prevent memory leak
    this.items = [];

    return results;
  }

  processItem(item) {
    // Processing logic
    return item;
  }
}
